import React, { Component } from "react";
import { Progress } from "reactstrap";
import { Link } from "react-router-dom";

import config from "./config";
import ControlsModal from "./ControlsModal";
import CheatsModal from "./CheatsModal";
import Emulator from "./Emulator";
import RomLibrary from "./RomLibrary";
import { PREDEFINED_CHEATS } from "./CheatManager";
import Peer from "simple-peer";
import MultiplayerModal from "./MultiplayerModal";
import "./RunPage.css";
import VirtualController from "./VirtualController";

function loadBinary(path, callback, handleProgress) {
  var req = new XMLHttpRequest();
  req.open("GET", path);
  req.overrideMimeType("text/plain; charset=x-user-defined");
  req.onload = function () {
    if (this.status === 200) {
      if (req.responseText.match(/^<!doctype html>/i)) {
        // Got HTML back, so it is probably falling back to index.html due to 404
        return callback(new Error("Page not found"));
      }

      callback(null, this.responseText);
    } else if (this.status === 0) {
      // Aborted, so ignore error
    } else {
      callback(new Error(req.statusText));
    }
  };
  req.onerror = function () {
    callback(new Error(req.statusText));
  };
  req.onprogress = handleProgress;
  req.send();
  return req;
}

/*
 * The UI for the emulator. Also responsible for loading ROM from URL or file.
 */
class RunPage extends Component {
  constructor(props) {
    super(props);
    this.state = {
      romName: null,
      romData: null,
      running: false,
      paused: false,
      controlsModalOpen: false,
      loading: true,
      loadedPercent: 3,
      error: null,
      cheatsModalOpen: false,
      cheatsList: [],
      newCheatName: "",
      newCheatCode: "",
      isFullscreen: false,
      aspectRatio: "4:3",
      windowWidth: window.innerWidth,
      multiplayerModalOpen: false,
      connectionState: "disconnected",
      inviteCode: "",
      responseCode: "",
      isHost: false,
      hasPeerConnected: false,
      isLocalChannelMode: false,
      connectionInterrupted: false,
      peer: null
    };
  }

  render() {
    return (
      <div className="RunPage">
        {/* <ul className="navbar-nav ml-auto mr-auto">
            <li className="navitem">
             <p><span className="navbar-text mr-3">{this.state.romName}</span></p> 
             <p><span className="navbar-text mr-3">DPad: Setas | Start: Enter | Select: CTRL Direito | Botão A: Z | Botão B: X</span></p>
            </li>
          </ul> */}
        <div className="runpage-container">

          {/* <Button
                outline
                color="primary"
                onClick={this.toggleControlsModal}
                className="mr-3"
              >
                Controles
              </Button>  */}

          {/* <Button
                outline
                color="primary"
                onClick={this.handlePauseResume}
                disabled={!this.state.running}
              >
                {this.state.paused ? "Continue" : "Pause"}
              </Button> */}
          {this.state.error ? (
            this.state.error
          ) : (
            <div
              id="screen-container-root"
              className={`screen-container${this.state.isFullscreen ? ' fullscreen-active' : ''}`}
              ref={el => {
                this.screenContainer = el;
              }}
            >
              <div className="emulator-menu" style={{ padding: this.state.isFullscreen ? "10px" : "0", background: this.state.isFullscreen ? "rgba(0,0,0,0.85)" : "transparent" }}>
                {!this.state.isFullscreen && (
                  <div>
                    <p style={{ margin: "0", fontWeight: "bold" }}>{this.state.romName}</p>
                  </div>
                )}
                {!this.state.isFullscreen && (
                  <p className="keyboard-shortcuts-info" style={{ margin: "0", fontSize: "0.9em", color: "#888" }}>Padrão: DPad: Setas | Start: Enter | Select: CTRL | Botão A: X | Botão B: Z</p>
                )}
                <div style={{ marginTop: this.state.isFullscreen ? "0" : "5px" }}>
                  {this.state.paused ? (
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handlePauseResume} className="no-underline"> Continuar Emulador ( <i className="fa fa-play-circle "></i> ) </a>
                  ) : (
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handlePauseResume} className="no-underline"> Pausar Emulador ( <i className="fa fa-pause"></i> ) </a>
                  )}

                  <span className="btn-fullscreen-container">
                    {" "}-{" "}
                    <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleFullscreen} className="no-underline">
                      {this.state.isFullscreen ? "Sair de Tela Cheia" : "Tela Cheia"}{" "}
                      ( <i className={this.state.isFullscreen ? "fa fa-compress" : "fa fa-arrows-alt"}></i> )
                    </a>
                    <span className="aspect-ratio-container">
                      {" "}( <a onClick={() => this.setAspectRatio(this.state.aspectRatio === '4:3' ? '16:9' : '4:3')} style={{ cursor: 'pointer', textDecoration: "none" }}>
                        {this.state.aspectRatio === '4:3' ? '16:9' : '4:3'}
                      </a> )
                    </span>
                  </span>

                  {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.handleReset} className="no-underline"> Resetar Emulador ( <i className="fa fa-refresh"></i> ) </a>
                  {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleControlsModal} className="no-underline"> Configurar Controles ( <i className="fa fa-gamepad"></i> )</a>
                  {!(!this.state.isHost && this.state.hasPeerConnected) && (
                    <span>
                      {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleCheatsModal} className="no-underline"> Trapaças / Cheats ( <i className="fa fa-magic"></i> )</a>
                    </span>
                  )}
                  {!this.state.hasPeerConnected && (
                    <span>
                      {" "}- <a style={{ "text-decoration": "none", cursor: "pointer" }} onClick={this.toggleMultiplayerModal} className="no-underline"> Jogar Online (Co-op) ( <i className="fa fa-users"></i> )</a>
                    </span>
                  )}
                  {this.state.hasPeerConnected && (
                    <span>
                      {" "}- <a style={{ "text-decoration": "none", cursor: "pointer", color: "#ff4d4d" }} onClick={() => this.handleDisconnect()} className="no-underline"> Desconectar Partida ( <i className="fa fa-times-circle"></i> )</a>
                    </span>
                  )}
                </div>
              </div>
              {this.state.loading ? (
                <Progress
                  value={this.state.loadedPercent}
                  style={{
                    position: "absolute",
                    width: "70%",
                    left: "15%",
                    top: "48%"
                  }}
                />
              ) : this.state.romData ? (
                <div className="emulator-wrapper" style={{ position: "relative", flexGrow: 1, minHeight: 0, display: "flex", justifyContent: "center", alignItems: "center", width: "100%" }}>
                  <Emulator
                    romData={this.state.romData}
                    paused={this.state.paused}
                    activeCheats={this.state.cheatsList}
                    aspectRatio={this.state.aspectRatio}
                    peer={this.state.peer}
                    isHost={this.state.isHost}
                    hasPeerConnected={this.state.hasPeerConnected}
                    isLocalChannelMode={this.state.isLocalChannelMode}
                    sendLocalChannelData={this.sendLocalChannelData}
                    sendLocalAudioData={this.sendLocalAudioData}
                    sendLocalVideoData={this.sendLocalVideoData}
                    onMount={this.handleEmulatorMount}
                    peerStream={this.state.peerStream}
                    ref={emulator => {
                      this.emulator = emulator;
                    }}
                  />

                  {this.state.connectionInterrupted && (
                    <div className="coop-disconnect-overlay">
                      <div className="coop-disconnect-box">
                        <div className="coop-disconnect-icon">🔌</div>
                        <h3>CONEXÃO INTERROMPIDA</h3>
                        <p>O outro jogador desconectou da partida. Escolha como deseja prosseguir:</p>
                        <button
                          className="custom-btn custom-btn-primary"
                          onClick={this.handleResumeSingleplayer}
                          style={{ width: "100%", marginBottom: this.state.isHost ? "12px" : "0" }}
                        >
                          Continuar no Modo Singleplayer
                        </button>
                        {this.state.isHost && (
                          <button
                            className="custom-btn custom-btn-outline-primary"
                            onClick={this.handleResumeWithoutReset}
                            style={{ width: "100%" }}
                          >
                            Continuar de onde parei
                          </button>
                        )}
                      </div>
                    </div>
                  )}

                  {/* TODO: lift keyboard and gamepad state up */}
                  {this.state.controlsModalOpen && (
                    <ControlsModal
                      isOpen={this.state.controlsModalOpen}
                      toggle={this.toggleControlsModal}
                      keys={this.emulator.keyboardController.keys}
                      setKeys={this.emulator.keyboardController.setKeys}
                      promptButton={this.emulator.gamepadController.promptButton}
                      gamepadConfig={this.emulator.gamepadController.gamepadConfig}
                      setGamepadConfig={
                        this.emulator.gamepadController.setGamepadConfig
                      }
                    />
                  )}
                  {this.state.cheatsModalOpen && (
                    <CheatsModal
                      isOpen={this.state.cheatsModalOpen}
                      toggle={this.toggleCheatsModal}
                      cheatsList={this.state.cheatsList}
                      handleToggleCheat={this.handleToggleCheat}
                      handleRemoveCheat={this.handleRemoveCheat}
                      handleAddCheat={this.handleAddCheat}
                      newCheatName={this.state.newCheatName}
                      newCheatCode={this.state.newCheatCode}
                      setNewCheatName={(val) => this.setState({ newCheatName: val })}
                      setNewCheatCode={(val) => this.setState({ newCheatCode: val })}
                    />
                  )}
                  <MultiplayerModal
                    isOpen={this.state.multiplayerModalOpen}
                    toggle={this.toggleMultiplayerModal}
                    connectionState={this.state.connectionState}
                    inviteCode={this.state.inviteCode}
                    responseCode={this.state.responseCode}
                    onCreateSession={this.handleCreateSession}
                    onJoinSession={this.handleJoinSession}
                    onAnswerSession={this.handleAnswerSession}
                    onDisconnect={this.handleDisconnect}
                    onConnectLocalTabs={this.handleConnectLocalTabs}
                  />
                </div>
              ) : null}
              <div style={{ zIndex: "10000" }} id="nes-pad">
                <VirtualController />
              </div>


            </div>
          )}
        </div>
        <nav
          className="navbar"
          ref={el => {
            this.navbar = el;
          }}
        >
        </nav>
      </div>
    );
  }

  componentDidMount() {
    window.addEventListener("resize", this.layout);
    document.addEventListener("fullscreenchange", this.handleFullscreenChange);
    document.addEventListener("webkitfullscreenchange", this.handleFullscreenChange);
    document.addEventListener("mozfullscreenchange", this.handleFullscreenChange);
    document.addEventListener("MSFullscreenChange", this.handleFullscreenChange);

    this.layout();
    this.load();

    window.addEventListener("message", this.handleWindowMessage);
    window.addEventListener("beforeunload", this.handleBeforeUnload);

    const params = new URLSearchParams(window.location.search);
    if (params.get("role") === "guest" && window.opener) {
      const rom = params.get("rom");
      this.handleAutoJoinLocal(rom);
    }
  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.layout);
    document.removeEventListener("fullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("webkitfullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("mozfullscreenchange", this.handleFullscreenChange);
    document.removeEventListener("MSFullscreenChange", this.handleFullscreenChange);

    if (this.currentRequest) {
      this.currentRequest.abort();
    }

    window.removeEventListener("message", this.handleWindowMessage);
    window.removeEventListener("beforeunload", this.handleBeforeUnload);

    if (this.closeCheckInterval) {
      clearInterval(this.closeCheckInterval);
    }
  }

  toggleFullscreen = () => {
    const element = this.screenContainer;
    if (!element) return;

    if (!document.fullscreenElement && !document.webkitFullscreenElement && !document.mozFullScreenElement && !document.msFullscreenElement) {
      if (element.requestFullscreen) {
        element.requestFullscreen();
      } else if (element.webkitRequestFullscreen) {
        element.webkitRequestFullscreen();
      } else if (element.mozRequestFullScreen) {
        element.mozRequestFullScreen();
      } else if (element.msRequestFullscreen) {
        element.msRequestFullscreen();
      }
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen();
      } else if (document.mozCancelFullScreen) {
        document.mozCancelFullScreen();
      } else if (document.msExitFullscreen) {
        document.msExitFullscreen();
      }
    }
  };

  handleFullscreenChange = () => {
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement);

    let newAspectRatio = this.state.aspectRatio;
    // Em telas médias (tablets), força a proporção 4:3 se entrar em fullscreen
    if (isFullscreen && window.innerWidth < 1024) {
      newAspectRatio = "4:3";
    }

    this.setState({ isFullscreen, aspectRatio: newAspectRatio }, () => {
      setTimeout(() => {
        this.layout();
      }, 100);
    });
  };

  setAspectRatio = (ratio) => {
    if (window.innerWidth >= 1024) {
      this.setState({ aspectRatio: ratio }, () => {
        this.layout();
      });
    }
  };

  layout = () => {
    const isTouch = (('ontouchstart' in window) ||
      (navigator.maxTouchPoints > 0) ||
      (navigator.msMaxTouchPoints > 0));

    const isMobile = window.innerWidth < 768;
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement);

    this.setState({ isFullscreen });

    const wrapperEl = document.querySelector('.emulator-wrapper');

    if (isFullscreen) {
      // Em modo Fullscreen: o screen-container sempre ocupa 100% da tela (100vh)
      this.screenContainer.style.height = "100vh";

      // Ajustamos o padding inferior do wrapper para evitar sobreposição do controle
      let paddingBottom = 0;
      if (isTouch) {
        const cntlrEl = document.querySelector('.cntlr');
        if (cntlrEl) {
          const cntlrBottom = parseFloat(window.getComputedStyle(cntlrEl).bottom) || 0;
          paddingBottom = cntlrEl.getBoundingClientRect().height + cntlrBottom + 15;
        }
      }
      if (wrapperEl) {
        wrapperEl.style.paddingBottom = `${paddingBottom}px`;
      }
    } else {
      // Fora de Fullscreen
      if (wrapperEl) {
        wrapperEl.style.paddingBottom = "0px";
      }

      // No fluxo normal da página do site
      let offset = 145; // Altura padrão do cabeçalho
      if (isTouch) {
        const cntlrEl = document.querySelector('.cntlr');
        if (cntlrEl) {
          const cntlrBottom = parseFloat(window.getComputedStyle(cntlrEl).bottom) || 0;
          offset += cntlrEl.getBoundingClientRect().height + cntlrBottom + 15;
        } else {
          offset += 165;
        }
      }

      this.screenContainer.style.height = `${window.innerHeight - offset}px`;
    }

    if (this.emulator) {
      requestAnimationFrame(() => {
        if (this.emulator) {
          this.emulator.fitInParent();
        }
      });
    }
  };

  load = () => {
    if (true) {
      const eggs = ["gradius", "lf", "contra", "dh", "duckh", "sevensix", "tn2", "cv"];
      var egg = eggs[Math.floor(Math.random() * eggs.length)];
      // var egg = "cv";

      const slug = egg;
      this.currentRomSlug = slug;
      const predefined = PREDEFINED_CHEATS[slug] || [];
      const cheatsList = predefined.map(cheat => ({ ...cheat, enabled: false }));
      this.setState({ cheatsList });

      const isLocalROM = /^local-/.test(slug);
      const romHash = slug.split("-")[1];
      const romInfo = isLocalROM
        ? RomLibrary.getRomInfoByHash(romHash)
        : config.ROMS[slug];

      if (!romInfo) {
        this.setState({ error: `ROM inválida: ${slug}` });
        return;
      }

      if (isLocalROM) {
        this.setState({ romName: romInfo.name });
        const localROMData = localStorage.getItem("blob-" + romHash);
        this.handleLoaded(localROMData);
      } else {
        this.setState({ romName: romInfo.description });
        this.currentRequest = loadBinary(
          romInfo.url,
          (err, data) => {
            if (err) {
              this.setState({ error: `Error loading ROM: ${err.message}` });
            } else {
              this.handleLoaded(data);
            }
          },
          this.handleProgress
        );
      }
    } else if (this.props.location.state && this.props.location.state.file) {
      let reader = new FileReader();
      reader.readAsBinaryString(this.props.location.state.file);
      reader.onload = e => {
        this.currentRequest = null;
        this.handleLoaded(reader.result);
      };
    } else {
      this.setState({ error: "No ROM provided" });
    }
  };

  handleProgress = e => {
    if (e.lengthComputable) {
      this.setState({ loadedPercent: (e.loaded / e.total) * 100 });
    }
  };

  handleLoaded = data => {
    this.setState({ running: true, loading: false, romData: data }, () => {
      setTimeout(() => {
        this.layout();
      }, 100);
    });
  };

  handlePauseResume = () => {
    this.setState({ paused: !this.state.paused });
  };

  handleReset = () => {
    if (this.emulator) {
      this.emulator.reset();
    }
  };

  toggleControlsModal = () => {
    const nextState = !this.state.controlsModalOpen;
    if (nextState) {
      this.wasPausedBeforeModal = this.state.paused;
      this.setState({ paused: true, controlsModalOpen: true });
    } else {
      const restorePause = this.wasPausedBeforeModal !== undefined ? this.wasPausedBeforeModal : false;
      this.setState({ paused: restorePause, controlsModalOpen: false });
    }
  };

  toggleCheatsModal = () => {
    const nextState = !this.state.cheatsModalOpen;
    if (nextState) {
      this.wasPausedBeforeModal = this.state.paused;
      this.setState({ paused: true, cheatsModalOpen: true });
    } else {
      const restorePause = this.wasPausedBeforeModal !== undefined ? this.wasPausedBeforeModal : false;
      this.setState({ paused: restorePause, cheatsModalOpen: false });
    }
  };

  handleToggleCheat = (index) => {
    const cheatsList = this.state.cheatsList.map((cheat, i) => {
      if (i === index) {
        return { ...cheat, enabled: !cheat.enabled };
      }
      return cheat;
    });
    this.setState({ cheatsList }, () => {
      const msg = `c,t,${index},${!this.state.cheatsList[index].enabled ? 1 : 0}`;
      if (this.state.isLocalChannelMode && this.state.isHost) {
        this.sendLocalCheatData(msg);
      } else if (this.state.peer && this.state.hasPeerConnected && this.state.isHost) {
        this.state.peer.send(msg);
      }
    });
  };

  handleAddCheat = (e) => {
    e.preventDefault();
    const name = this.state.newCheatName || "";
    const code = (this.state.newCheatCode || "").trim().toUpperCase();

    if (!name || !code) {
      alert("Por favor, preencha o nome e o código do cheat.");
      return;
    }

    const GG_REGEX = /^[APZLGITYEOXUKSVN]{6,8}$/;
    if (!GG_REGEX.test(code)) {
      alert("Código Game Genie inválido! O código deve ter 6 ou 8 letras e conter apenas os caracteres permitidos: A P Z L G I T Y E O X U K S V N");
      return;
    }

    const newCheat = { name, code, enabled: true, custom: true };
    this.setState({
      cheatsList: [...this.state.cheatsList, newCheat],
      newCheatName: "",
      newCheatCode: ""
    }, () => {
      const msg = `c,a,${name},${code}`;
      if (this.state.isLocalChannelMode && this.state.isHost) {
        this.sendLocalCheatData(msg);
      } else if (this.state.peer && this.state.hasPeerConnected && this.state.isHost) {
        this.state.peer.send(msg);
      }
    });
  };

  handleRemoveCheat = (index) => {
    const cheatsList = this.state.cheatsList.filter((_, i) => i !== index);
    this.setState({ cheatsList }, () => {
      const msg = `c,r,${index}`;
      if (this.state.isLocalChannelMode && this.state.isHost) {
        this.sendLocalCheatData(msg);
      } else if (this.state.peer && this.state.hasPeerConnected && this.state.isHost) {
        this.state.peer.send(msg);
      }
    });
  };

  safeBtoa = (str) => {
    try {
      return btoa(unescape(encodeURIComponent(str)));
    } catch (e) {
      console.error("Safe btoa failed:", e);
      return btoa(str);
    }
  };

  safeAtob = (str) => {
    try {
      return decodeURIComponent(escape(atob(str)));
    } catch (e) {
      console.error("Safe atob failed:", e);
      return atob(str);
    }
  };

  toggleMultiplayerModal = () => {
    this.setState(prevState => ({
      multiplayerModalOpen: !prevState.multiplayerModalOpen
    }));
  };

  unmaskLocalIPs = async () => {
    try {
      if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        if (stream) {
          stream.getTracks().forEach(track => track.stop());
        }
      }
    } catch (e) {
      console.warn("Failed to unmask local IPs (microphone permission denied):", e);
    }
  };

  handleCreateSession = async () => {
    this.setState({ connectionState: "generating", isHost: true });
    
    await this.unmaskLocalIPs();
    
    const slug = this.currentRomSlug || "contra";
    
    const iceServers = [
      { urls: "stun:stun.l.google.com:19302" },
      { urls: "stun:stun1.l.google.com:19302" },
      { urls: "stun:stun2.l.google.com:19302" },
      { urls: "stun:stun3.l.google.com:19302" },
      { urls: "stun:stun4.l.google.com:19302" },
      {
        urls: "turns:openrelay.metered.ca:443",
        username: "openrelayproject",
        credential: "openrelayproject"
      },
      {
        urls: "turns:openrelay.metered.ca:443?transport=tcp",
        username: "openrelayproject",
        credential: "openrelayproject"
      }
    ];

    const peer = new Peer({
      initiator: true,
      trickle: false,
      iceCompleteTimeout: 8000,
      config: { iceServers }
    });

    peer.on("signal", (data) => {
      const inviteObj = { sdp: data, rom: slug };
      const inviteCode = this.safeBtoa(JSON.stringify(inviteObj));
      this.setState({
        inviteCode,
        connectionState: "waiting-for-answer"
      });
    });

    peer.on("connect", () => {
      this.setState({
        connectionState: "connected",
        hasPeerConnected: true
      }, () => {
        try {
          peer.send(`c,sync,${JSON.stringify(this.state.cheatsList)}`);
        } catch (e) {
          console.error("Failed to send initial cheats sync:", e);
        }
        peer.send("g,s");
        if (this.emulator) {
          this.emulator.handleStartGame();
        }
      });
    });

    peer.on("data", (data) => {
      const str = data.toString();
      if (str === "d") {
        this.handleDisconnect();
        return;
      }
      if (str.startsWith("i,") || str.startsWith("g,")) {
        if (this.emulator) {
          this.emulator.handleRemoteData(str);
        }
      } else if (str.startsWith("c,")) {
        this.handleRemoteCheat(str);
      }
    });

    peer.on("close", () => {
      console.warn("HOST PEER: Conexão fechada");
      this.handleDisconnect();
    });
    peer.on("error", (err) => {
      console.error("HOST PEER ERROR:", err);
      this.handleDisconnect();
    });

    this.setState({ peer });
  };

  handleJoinSession = async (inviteInput) => {
    try {
      this.setState({ connectionState: "generating-answer", isHost: false });
      
      await this.unmaskLocalIPs();
      
      const inviteObj = JSON.parse(this.safeAtob(inviteInput.trim()));
      const { sdp, rom } = inviteObj;

      const romInfo = config.ROMS[rom];
      if (romInfo) {
        this.currentRomSlug = rom;
        const predefined = PREDEFINED_CHEATS[rom] || [];
        const cheatsList = predefined.map(cheat => ({ ...cheat, enabled: false }));
        this.setState({ cheatsList, romName: romInfo.description, loading: true });
        if (this.currentRequest) {
          this.currentRequest.abort();
        }
        this.currentRequest = loadBinary(
          romInfo.url,
          (err, data) => {
            if (err) {
              this.setState({ error: `Error loading ROM: ${err.message}` });
            } else {
              this.handleLoaded(data);
            }
          },
          this.handleProgress
        );
      }

      const iceServers = [
        { urls: "stun:stun.l.google.com:19302" },
        { urls: "stun:stun1.l.google.com:19302" },
        { urls: "stun:stun2.l.google.com:19302" },
        { urls: "stun:stun3.l.google.com:19302" },
        { urls: "stun:stun4.l.google.com:19302" },
        {
          urls: "turns:openrelay.metered.ca:443",
          username: "openrelayproject",
          credential: "openrelayproject"
        },
        {
          urls: "turns:openrelay.metered.ca:443?transport=tcp",
          username: "openrelayproject",
          credential: "openrelayproject"
        }
      ];

      const peer = new Peer({
        initiator: false,
        trickle: false,
        iceCompleteTimeout: 8000,
        config: { iceServers }
      });

      peer.on("signal", (data) => {
        const responseCode = this.safeBtoa(JSON.stringify(data));
        this.setState({ responseCode });
      });

      peer.on("connect", () => {
        this.setState({
          connectionState: "connected",
          hasPeerConnected: true
        }, () => {
          if (this.emulator) {
            this.emulator.handleStartGame();
          }
        });
      });

      peer.on("data", (data) => {
        const str = data.toString();
        if (str === "d") {
          this.handleDisconnect();
          return;
        }
        if (str.startsWith("v,")) {
          if (this.emulator) {
            this.emulator.handleGuestVideoFrame(str.substring(2));
          }
          return;
        } else if (str.startsWith("i,") || str.startsWith("g,")) {
          if (this.emulator) {
            this.emulator.handleRemoteData(str);
          }
          return;
        } else if (str.startsWith("c,")) {
          this.handleRemoteCheat(str);
          return;
        }

        // Se não for texto, processa como amostras de áudio binárias de 16 bits PCM
        if (this.emulator) {
          try {
            const alignedBuffer = new Uint8Array(data).buffer;
            const int16Data = new Int16Array(alignedBuffer);
            const half = int16Data.length / 2;
            const left = new Float32Array(half);
            const right = new Float32Array(half);
            for (let i = 0; i < half; i++) {
              let valL = int16Data[i];
              left[i] = valL < 0 ? valL / 0x8000 : valL / 0x7FFF;

              let valR = int16Data[half + i];
              right[i] = valR < 0 ? valR / 0x8000 : valR / 0x7FFF;
            }
            this.emulator.handleGuestAudioSamples(left, right);
          } catch (e) {
            console.error("Failed to parse binary audio packet:", e);
          }
        }
      });



      peer.on("close", () => {
        console.warn("GUEST PEER: Conexão fechada");
        this.handleDisconnect();
      });
      peer.on("error", (err) => {
        console.error("GUEST PEER ERROR:", err);
        this.handleDisconnect();
      });

      peer.signal(sdp);
      this.setState({ peer });

    } catch (e) {
      alert("Código de convite inválido.");
      this.setState({ connectionState: "disconnected" });
    }
  };

  handleAnswerSession = (answerInput) => {
    try {
      const answerSdp = JSON.parse(this.safeAtob(answerInput.trim()));
      if (this.state.peer) {
        this.state.peer.signal(answerSdp);
        this.setState({ connectionState: "connecting" });
      }
    } catch (e) {
      alert("Código de resposta inválido.");
    }
  };

  handleDisconnect = (localOnly = false) => {
    const wasConnected = this.state.hasPeerConnected;

    if (this.state.peer) {
      try {
        this.state.peer.send("d");
      } catch (e) {}
      
      const p = this.state.peer;
      setTimeout(() => {
        try {
          p.destroy();
        } catch (e) {}
      }, 100);
    }
    if (this.state.isLocalChannelMode && !localOnly) {
      try {
        const payload = { source: 'nes-coop', type: 'local-disconnect' };
        if (this.state.isHost && this.guestWindow) {
          this.guestWindow.postMessage(payload, window.location.origin);
        } else if (!this.state.isHost && window.opener) {
          window.opener.postMessage(payload, window.location.origin);
        }
      } catch (e) {}
    }

    if (this.closeCheckInterval) {
      clearInterval(this.closeCheckInterval);
      this.closeCheckInterval = null;
    }

    if (this.guestAudio) {
      try {
        this.guestAudio.pause();
        this.guestAudio.srcObject = null;
        if (this.guestAudio.parentNode) {
          this.guestAudio.parentNode.removeChild(this.guestAudio);
        }
      } catch (e) {}
      this.guestAudio = null;
    }

    this.setState({
      peer: null,
      connectionState: "disconnected",
      inviteCode: "",
      responseCode: "",
      hasPeerConnected: false,
      isLocalChannelMode: false,
      paused: wasConnected ? true : this.state.paused,
      connectionInterrupted: wasConnected ? true : this.state.connectionInterrupted
    });
  };
  handleConnectLocalTabs = () => {
    const slug = this.currentRomSlug || "contra";
    const guestWindow = window.open(
      `${window.location.origin}${window.location.pathname}?role=guest&rom=${slug}${window.location.hash}`,
      '_blank'
    );
    this.guestWindow = guestWindow;

    if (this.closeCheckInterval) {
      clearInterval(this.closeCheckInterval);
    }
    this.closeCheckInterval = setInterval(() => {
      if (this.guestWindow && this.guestWindow.closed) {
        clearInterval(this.closeCheckInterval);
        this.guestWindow = null;
        if (this.state.isLocalChannelMode && this.state.hasPeerConnected) {
          this.handleDisconnect(true);
        }
      }
    }, 1000);

    this.setState({
      isHost: true,
      isLocalChannelMode: true,
      connectionState: "connecting"
    });
  };

  sendLocalChannelData = (dataStr) => {
    const payload = { source: 'nes-coop', type: 'local-game-data', data: dataStr };
    try {
      if (this.state.isHost && this.guestWindow) {
        this.guestWindow.postMessage(payload, window.location.origin);
      } else if (!this.state.isHost && window.opener) {
        window.opener.postMessage(payload, window.location.origin);
      }
    } catch (e) {
      console.error("Failed to post message:", e);
    }
  };

  sendLocalAudioData = (left, right) => {
    const payload = { source: 'nes-coop', type: 'local-audio-data', left, right };
    try {
      if (this.state.isHost && this.guestWindow) {
        this.guestWindow.postMessage(payload, window.location.origin);
      }
    } catch (e) {
      console.error("Failed to post local audio samples:", e);
    }
  };

  sendLocalVideoData = (jpegData) => {
    const payload = { source: 'nes-coop', type: 'local-video-data', jpegData };
    try {
      if (this.state.isHost && this.guestWindow) {
        this.guestWindow.postMessage(payload, window.location.origin);
      }
    } catch (e) {
      console.error("Failed to post local video frame:", e);
    }
  };

  sendLocalCheatData = (dataStr) => {
    const payload = { source: 'nes-coop', type: 'local-cheat-data', data: dataStr };
    try {
      if (this.state.isHost && this.guestWindow) {
        this.guestWindow.postMessage(payload, window.location.origin);
      }
    } catch (e) {
      console.error("Failed to post cheat message:", e);
    }
  };

  handleAutoJoinLocal = (rom) => {
    if (this.closeCheckInterval) {
      clearInterval(this.closeCheckInterval);
    }
    this.closeCheckInterval = setInterval(() => {
      if (!window.opener || window.opener.closed) {
        clearInterval(this.closeCheckInterval);
        if (this.state.isLocalChannelMode && this.state.hasPeerConnected) {
          this.handleDisconnect(true);
        }
      }
    }, 1000);

    this.setState({
      isHost: false,
      isLocalChannelMode: true,
      connectionState: "connecting",
      hasPeerConnected: true,
      multiplayerModalOpen: false
    }, () => {
      const romInfo = config.ROMS[rom];
      if (romInfo) {
        this.currentRomSlug = rom;
        const predefined = PREDEFINED_CHEATS[rom] || [];
        const cheatsList = predefined.map(cheat => ({ ...cheat, enabled: false }));
        this.setState({ cheatsList, romName: romInfo.description, loading: true });
        if (this.currentRequest) {
          this.currentRequest.abort();
        }
        this.currentRequest = loadBinary(
          romInfo.url,
          (err, data) => {
            if (err) {
              this.setState({ error: `Error loading ROM: ${err.message}` });
            } else {
              this.handleLoaded(data);
            }
          },
          this.handleProgress
        );
      }
    });
  };

  handleWindowMessage = (event) => {
    if (event.origin !== window.location.origin) return;
    const msg = event.data;
    if (!msg || msg.source !== 'nes-coop') return;

    if (msg.type === "local-connect-accept") {
      if (this.state.isHost && this.state.isLocalChannelMode) {
        this.setState({
          connectionState: "connected",
          hasPeerConnected: true,
          multiplayerModalOpen: false
        }, () => {
          const cheatsPayload = {
            source: 'nes-coop',
            type: 'local-cheat-sync',
            cheats: this.state.cheatsList
          };
          if (this.guestWindow) {
            this.guestWindow.postMessage(cheatsPayload, window.location.origin);
          }

          const payload = { source: 'nes-coop', type: 'local-game-signal', data: 'g,s' };
          if (this.guestWindow) {
            this.guestWindow.postMessage(payload, window.location.origin);
          }
          if (this.emulator) {
            this.emulator.handleStartGame();
          }
        });
      }
    } else if (msg.type === "local-cheat-sync") {
      this.setState({ cheatsList: msg.cheats });
    } else if (msg.type === "local-game-data") {
      if (this.state.hasPeerConnected && this.state.isLocalChannelMode) {
        if (this.emulator) {
          this.emulator.handleRemoteData(msg.data);
        }
      }
    } else if (msg.type === "local-audio-data") {
      if (this.state.hasPeerConnected && this.state.isLocalChannelMode && !this.state.isHost) {
        if (this.emulator) {
          this.emulator.handleGuestAudioSamples(msg.left, msg.right);
        }
      }
    } else if (msg.type === "local-video-data") {
      if (this.state.hasPeerConnected && this.state.isLocalChannelMode && !this.state.isHost) {
        if (this.emulator) {
          this.emulator.handleGuestVideoFrame(msg.jpegData);
        }
      }
    } else if (msg.type === "local-game-signal") {
      if (this.state.hasPeerConnected && this.state.isLocalChannelMode) {
        if (this.emulator) {
          this.emulator.handleRemoteData(msg.data);
        }
      }
    } else if (msg.type === "local-cheat-data") {
      if (this.state.hasPeerConnected && this.state.isLocalChannelMode) {
        this.handleRemoteCheat(msg.data);
      }
    } else if (msg.type === "local-disconnect") {
      this.handleDisconnect(true);
    }
  };

  handleEmulatorMount = () => {
    if (this.state.isLocalChannelMode && !this.state.isHost && window.opener) {
      const payload = { source: 'nes-coop', type: 'local-connect-accept' };
      window.opener.postMessage(payload, window.location.origin);
    }
  };

  handleBeforeUnload = () => {
    if (this.state.peer) {
      try {
        this.state.peer.destroy();
      } catch (e) {}
    }
    if (this.state.isLocalChannelMode && this.state.hasPeerConnected) {
      const payload = { source: 'nes-coop', type: 'local-disconnect' };
      try {
        if (this.state.isHost && this.guestWindow) {
          this.guestWindow.postMessage(payload, window.location.origin);
        } else if (!this.state.isHost && window.opener) {
          window.opener.postMessage(payload, window.location.origin);
        }
      } catch (e) {}
    }
  };

  handleResumeSingleplayer = () => {
    try {
      window.history.replaceState({}, document.title, window.location.pathname + window.location.hash);
    } catch (e) {
      console.error(e);
    }
    const wasHost = this.state.isHost;
    this.setState({
      connectionInterrupted: false,
      paused: false
    }, () => {
      if (this.emulator) {
        if (wasHost) {
          this.emulator.reset();
        } else {
          this.emulator.initLocalSingleplayer();
        }
      }
    });
  };

  handleResumeWithoutReset = () => {
    try {
      window.history.replaceState({}, document.title, window.location.pathname + window.location.hash);
    } catch (e) {
      console.error(e);
    }
    this.setState({
      connectionInterrupted: false,
      paused: false
    });
  };

  handleRemoteCheat = (str) => {
    const parts = str.split(",");
    const op = parts[1];
    if (op === "sync") {
      try {
        const cheatsList = JSON.parse(str.substring("c,sync,".length));
        this.setState({ cheatsList });
      } catch (e) {
        console.error("Failed to parse cheat sync payload:", e);
      }
    } else if (op === "t") {
      const index = parseInt(parts[2], 10);
      const enabled = parts[3] === "1";
      this.setState(prevState => {
        const cheatsList = prevState.cheatsList.map((cheat, i) => {
          if (i === index) {
            return { ...cheat, enabled };
          }
          return cheat;
        });
        return { cheatsList };
      });
    } else if (op === "a") {
      const name = parts[2];
      const code = parts[3];
      const newCheat = { name, code, enabled: true, custom: true };
      this.setState(prevState => ({
        cheatsList: [...prevState.cheatsList, newCheat]
      }));
    } else if (op === "r") {
      const index = parseInt(parts[2], 10);
      this.setState(prevState => ({
        cheatsList: prevState.cheatsList.filter((_, i) => i !== index)
      }));
    }
  };
}

export default RunPage;
