import RingBuffer from "ringbufferjs";
import { handleError } from "./utils";

export default class Speakers {
  constructor({ onBufferUnderrun }) {
    this.onBufferUnderrun = onBufferUnderrun;
    this.bufferSize = 8192;
    this.buffer = new RingBuffer(this.bufferSize * 2);
  }

  getSampleRate() {
    if (!window.AudioContext) {
      return 44100;
    }
    let myCtx = new window.AudioContext();
    let sampleRate = myCtx.sampleRate;
    myCtx.close();
    return sampleRate;
  }

  start() {
    // Audio is not supported
    if (!window.AudioContext) {
      return;
    }
    this.audioCtx = new window.AudioContext();
    this.scriptNode = this.audioCtx.createScriptProcessor(1024, 0, 2);
    this.scriptNode.onaudioprocess = this.onaudioprocess;
    this.scriptNode.connect(this.audioCtx.destination);

    // Inicialização ansiosa do stream de áudio de saída
    this.audioStreamDest = this.audioCtx.createMediaStreamDestination();
    this.scriptNode.connect(this.audioStreamDest);

    // Garante que o AudioContext seja resumido ao interagir com a tela (resolvendo bloqueio de autoplay do navegador)
    const resumeAudio = () => {
      if (this.audioCtx && this.audioCtx.state === "suspended") {
        this.audioCtx.resume()
          .then(() => {
            console.log("AudioContext resumed successfully");
            cleanupListeners();
          })
          .catch(e => console.error("Failed to resume AudioCtx:", e));
      } else if (this.audioCtx && this.audioCtx.state === "running") {
        cleanupListeners();
      }
    };

    const cleanupListeners = () => {
      document.removeEventListener("click", resumeAudio, { capture: true });
      document.removeEventListener("keydown", resumeAudio, { capture: true });
      document.removeEventListener("touchstart", resumeAudio, { capture: true });
      document.removeEventListener("mousedown", resumeAudio, { capture: true });
    };

    document.addEventListener("click", resumeAudio, { capture: true });
    document.addEventListener("keydown", resumeAudio, { capture: true });
    document.addEventListener("touchstart", resumeAudio, { capture: true });
    document.addEventListener("mousedown", resumeAudio, { capture: true });

    if (this.audioCtx.state === "suspended") {
      this.audioCtx.resume().catch(() => {});
    }
  }

  stop() {
    if (this.scriptNode) {
      try {
        this.scriptNode.disconnect(this.audioCtx.destination);
      } catch (e) {}
      if (this.audioStreamDest) {
        try {
          this.scriptNode.disconnect(this.audioStreamDest);
        } catch (e) {}
        this.audioStreamDest = null;
      }
      this.scriptNode.onaudioprocess = null;
      this.scriptNode = null;
    }
    if (this.audioCtx) {
      this.audioCtx.close().catch(handleError);
      this.audioCtx = null;
    }
  }

  getAudioStream() {
    if (!this.audioStreamDest) return null;
    return this.audioStreamDest.stream;
  }

  writeSample = (left, right) => {
    if (this.buffer.size() / 2 >= this.bufferSize) {
      this.buffer.deqN(this.bufferSize / 2);
    }
    this.buffer.enq(left);
    this.buffer.enq(right);
  };

  writeSamples = (left, right) => {
    const size = left.length;
    if ((this.buffer.size() + size * 2) / 2 >= this.bufferSize) {
      try {
        this.buffer.deqN(size * 2);
      } catch (e) {}
    }
    for (let i = 0; i < size; i++) {
      this.buffer.enq(left[i]);
      this.buffer.enq(right[i]);
    }
  };

  onaudioprocess = e => {
    var left = e.outputBuffer.getChannelData(0);
    var right = e.outputBuffer.getChannelData(1);
    var size = left.length;

    // We're going to buffer underrun. Attempt to fill the buffer.
    if (this.buffer.size() < size * 2 && this.onBufferUnderrun) {
      this.onBufferUnderrun(this.buffer.size(), size * 2);
    }

    try {
      var samples = this.buffer.deqN(size * 2);
    } catch (e) {
      // onBufferUnderrun failed to fill the buffer, so handle a real buffer
      // underrun

      // ignore empty buffers... assume audio has just stopped
      for (var j = 0; j < size; j++) {
        left[j] = 0;
        right[j] = 0;
      }
      return;
    }
    for (var i = 0; i < size; i++) {
      left[i] = samples[i * 2];
      right[i] = samples[i * 2 + 1];
    }

    if (this.onAudioDataCallback) {
      const leftCopy = new Float32Array(left);
      const rightCopy = new Float32Array(right);
      this.onAudioDataCallback(leftCopy, rightCopy);
    }
  };
}
